# Shape implementations - cross-module inheritance and interface implementation

from types import IDrawable, IResizable, IPositionable, Color, Point

@abstract
class Shape(IDrawable, IPositionable):
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @virtual
    def area(self) -> float:
        return 0.0

    def move(self, dx: int, dy: int) -> None:
        self.position.x += dx
        self.position.y += dy

    @abstract
    def get_name(self) -> str: ...

class Circle(Shape, IResizable):
    radius: float

    def __init__(self, color: Color, position: Point, radius: float):
        super().__init__(color, position)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_name(self) -> str:
        return "Circle"

    def resize(self, factor: float) -> None:
        self.radius *= factor

    @override
    def draw(self) -> str:
        return f"Circle at ({self.position.x}, {self.position.y})"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, color: Color, position: Point, width: float, height: float):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def get_name(self) -> str:
        return "Rectangle"

    @override
    def draw(self) -> str:
        return f"Rectangle at ({self.position.x}, {self.position.y})"

