# Drawing utilities and factories - uses shapes from another module

from types import Color, Point
from shapes import Shape, Circle, Rectangle

class Canvas:
    items: list[Shape]

    def __init__(self):
        self.items = []

    def add(self, item: Shape) -> None:
        self.items.append(item)

    def render_all(self) -> list[str]:
        results: list[str] = []
        for item in self.items:
            results.append(item.draw())
        return results

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.items:
            total += shape.area()
        return total

class ShapeFactory:
    @static
    def create_circle(color: Color, x: float, y: float, radius: float) -> Circle:
        pos: Point = Point(x, y)
        return Circle(color, pos, radius)

    @static
    def create_rectangle(color: Color, x: float, y: float, width: float, height: float) -> Rectangle:
        pos: Point = Point(x, y)
        return Rectangle(color, pos, width, height)
